import React from "react";
import "./SoftwareSkill.scss";
import { skillsSection } from "../../portfolio";
import { Icon } from '@iconify/react';
import tensorflowIcon from '@iconify-icons/simple-icons/tensorflow';
import pythonIcon from '@iconify-icons/simple-icons/python';
import languageCpp from '@iconify-icons/mdi/language-cpp';
import opencvIcon from '@iconify-icons/simple-icons/opencv';
import unityIcon from '@iconify-icons/simple-icons/unity';

export default function SoftwareSkill() {
  return (
    <div>
      <div className="software-skills-main-div">
        <ul className="dev-icons">
          {skillsSection.softwareSkills.map((skills, i) => {
            let iconName;
            switch (skills.fontAwesomeClassname) {
              case 'tf':
                iconName = tensorflowIcon;
                break;
              case 'py':
                iconName = pythonIcon;
                break;
              case 'cpp':
                iconName = languageCpp;
                break;
              case 'opencv':
                iconName = opencvIcon;
                break;
              case 'unity':
                iconName = unityIcon;
                break;
              default:
                break;
            }
            return (
              <li
                key={i}
                className="software-skill-inline"
                name={skills.skillName}
              >
                <Icon icon={iconName} />
                <p>{skills.skillName}</p>
              </li>
            );
          })}
        </ul>
      </div>
    </div>
  );
}
